// Filtra leads sin respuesta hace 2+ días y sin marca de seguimiento cerrado
const hoy = new Date();
return items.filter(i => {
  const j = i.json;
  if ((j.estado || '').toLowerCase() === 'cerrado') return false;
  if ((j.ultimo_seguimiento || '') === 'hecho') return false;
  const fecha = new Date(j.fecha);
  const dias = (hoy - fecha) / (1000*60*60*24);
  return dias >= 2;
}).map(i => ({ json: {
  to: i.json.contacto,
  nombre: i.json.nombre || '',
  interes: i.json.interes || 'tu consulta',
  tipo: 'reactivacion'
}}));

// Clientes con proyecto entregado/en curso hace 30+ días y sin encuesta este mes
const hoy = new Date();
return items.filter(i => {
  const j = i.json;
  const est = j.estado_proyecto || '';
  if (est !== 'En curso' && est !== 'Entregado' && est !== 'Cerrado') return false;
  const inicio = new Date(j.fecha_alta);
  const dias = (hoy - inicio) / (1000*60*60*24);
  return dias >= 30 && (j.encuesta_mes || '') !== (hoy.getFullYear()+'-'+(hoy.getMonth()+1));
}).map(i => ({ json: {
  to: i.json.contacto,
  nombre: i.json.nombre || '',
  tipo: 'satisfaccion'
}}));

// Clientes con proyecto ENTREGADO y saldo pendiente > 0 → recordar el 50% restante
return items.filter(i => {
  const j = i.json;
  return (j.estado_proyecto || '') === 'Entregado' && Number(j.saldo_pendiente) > 0;
}).map(i => ({ json: {
  to: i.json.contacto,
  nombre: i.json.nombre || '',
  saldo: i.json.saldo_pendiente,
  tipo: 'saldo'
}}));

// Arma el mensaje según el tipo. Para reactivación hace A/B testing:
// alterna entre 2 versiones y registra cuál se mandó (variante A/B) para medir cuál convierte más.
return items.map((i, idx) => {
  const j = i.json;
  let body; let variante = '';
  if (j.tipo === 'satisfaccion') {
    body = `¡Hola ${j.nombre}! 👋 Soy Redi, de RedLabs. ¿Cómo venís con la automatización? Del 1 al 10, ¿qué nota nos pondrías? Si hay algo para mejorar, contame y lo resolvemos.`;
  } else if (j.tipo === 'saldo') {
    body = `¡Hola ${j.nombre}! 👋 Soy Redi, de RedLabs. Te recuerdo que quedó pendiente el 50% restante (u$s ${j.saldo}) de tu proyecto ya entregado. Cuando quieras te paso los datos para la transferencia. ¡Gracias!`;
  } else {
    // A/B: variante según índice (par = A, impar = B). Simple y balanceado.
    const esA = idx % 2 === 0;
    variante = esA ? 'A' : 'B';
    body = esA
      ? `¡Hola ${j.nombre}! 👋 Soy Redi, de RedLabs. Quería saber si seguís interesado en ${j.interes}. Si querés, te muestro opciones o coordinamos una llamada corta con Luca. ¿Te sirve?`
      : `¡Hola ${j.nombre}! 👋 Soy Redi, de RedLabs. Te dejé pensando con ${j.interes}, ¿no? 😄 Si querés lo vemos juntos en 2 minutos y te paso un precio a tu medida. ¿Lo charlamos?`;
  }
  return { json: { to: j.to, body, tipo: j.tipo, variante } };
});
